using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        // .NET 9: StatusStrip no longer defaults to ToolStripProfessionalRenderer.
        // Explicitly set the renderer to preserve the previous appearance.
        _statusStrip = new StatusStrip();
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        ToolStripManager.Renderer = new ToolStripProfessionalRenderer();

        Controls.Add(_statusStrip);
    }

    [DesignerSerializationVisibility(DesignerSerializationVisibility.Visible)]
    public string DisplayName { get; set; }

    [DesignerSerializationVisibility(DesignerSerializationVisibility.Visible)]
    public int MaxItems { get; set; }

    // .NET 9: IWindowsFormsEditorService.DropDownControl(null) now throws
    // ArgumentNullException. Always guard against null before calling.
    public static void SafeDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

